def module_available(name):
    return importlib.util.find_spec(name) is not None


def ensure_dependencies():
    missing = [spec for module, spec in DEFAULT_PACKAGES if not module_available(module)]
    if not missing:
        return
    print("Missing Python packages:")
    for item in missing:
        print(f"  - {item}")
    auto = os.environ.get("TPARC_AUTO_INSTALL", "1") == "1"
    if not auto:
        print("Install them with:")
        print(f"  {sys.executable} -m pip install " + " ".join(missing))
        raise SystemExit(1)
    print("Attempting one-time pip install. Set TPARC_AUTO_INSTALL=0 to disable this.")
    subprocess.check_call([sys.executable, "-m", "pip", "install", *missing])


def runtime_dir():
    configured = os.environ.get("TPARC_SINGLE_RUNTIME")
    if configured:
        return Path(configured).expanduser().resolve()
    return Path.home() / ".tparc_rms_single"


def unpack_app(target):
    marker = target / ".bundle_version"
    if marker.exists() and marker.read_text(encoding="utf-8") == APP_VERSION and (target / "app" / "__init__.py").exists():
        return
    if target.exists():
        shutil.rmtree(target)
    target.mkdir(parents=True, exist_ok=True)
    data = base64.b64decode("".join(APP_ZIP_B64.split()))
    zip_path = target / "bundle.zip"
    zip_path.write_bytes(data)
    with zipfile.ZipFile(zip_path) as zf:
        zf.extractall(target)
    zip_path.unlink(missing_ok=True)
    marker.write_text(APP_VERSION, encoding="utf-8")


def configure_environment(target):
    os.environ.setdefault("TPARC_ALLOW_INSECURE_DEV", "1")
    os.environ.setdefault("TPARC_SERIAL_BAUD", "115200")
    os.environ.setdefault("TPARC_DB", str(target / "tparc.sqlite3"))
    os.environ.setdefault("TPARC_SESSION_MINUTES", "30")


def main():
    target = runtime_dir()
    ensure_dependencies()
    unpack_app(target)
    configure_environment(target)
    sys.path.insert(0, str(target))
    from app import create_app, socketio

    app = create_app()
    host = os.environ.get("TPARC_HOST", "0.0.0.0")
    port = int(os.environ.get("TPARC_PORT", "5000"))
    url = f"http://127.0.0.1:{port}"
    serial_display = app.config.get("SERIAL_PORT") or "auto-detect/simulated"
    print("TP-ARC RMS is starting")
    print(f"  Local URL: {url}")
    print(f"  Network URL: http://<rms-host>:{port}")
    print(f"  Serial: {serial_display} @ {os.environ.get('TPARC_SERIAL_BAUD')}")
    print(f"  Runtime: {target}")
    print("  Default users: tparc/tparc0322, operator/change-me-operator, viewer/change-me-viewer")
    print("  Configuration guide extracts to CONFIGURATION.md in the runtime folder")
    print("Press Ctrl+C in this window to stop.")
    if os.environ.get("TPARC_OPEN_BROWSER", "1") == "1":
        try:
            webbrowser.open(url)
        except Exception:
            pass
    socketio.run(app, host=host, port=port, allow_unsafe_werkzeug=True)


if __name__ == "__main__":
    main()
